import lxml.etree as ET

def process_soap_request(xml):
    # Parse the SOAP envelope and extract the message body
    root = ET.fromstring(xml)
    body = root.find(".//Body")
    if body is not None:
        return body.text
    else:
        return "Invalid SOAP request"